const store = new NonceStore();
const insertSpy = vi.spyOn(store, 'insert');
// Step 1: verify inserts the nonce
const verifyResult = await verifyEip3009Authorization(payload, { ...verifyOpts, nonceStore: store });
expect(verifyResult.ok).toBe(true);
// Step 2: settle fails, but must not touch the store
const insertCallsBefore = insertSpy.mock.calls.length;
const result = await settleOnChain(payload, SIGNER_ADDR, settleOpts);
expect(result).toMatchObject({ ok: false });
expect(insertSpy).toHaveBeenCalledTimes(insertCallsBefore); // no new calls from settle

const hasSpy = vi.spyOn(opts.nonceStore, 'has').mockImplementation(() => {
  order.push('has');
  // Queue a microtask that would interleave if there's an await after has
  Promise.resolve().then(() => order.push('sentinel'));
  return false;
});
const insertSpy = vi.spyOn(opts.nonceStore, 'insert').mockImplementation(() => {
  order.push('insert');
});
await verifyEip3009Authorization(payload, opts);
// If no await between has+insert, order is ['has','insert','sentinel'].
// If there IS an await between them, order would be ['has','sentinel','insert'].
const hasIdx = order.indexOf('has');
const sentinelIdx = order.indexOf('sentinel');
const insertIdx = order.indexOf('insert');
expect(insertIdx).toBeLessThan(sentinelIdx); // insert fires before sentinel drains

it('ContractFunctionExecutionError with no decodable reason falls back to gas_estimate_revert', async () => {
  walletWriteSpy.mockImplementation(async () => {
    // cause.message is deliberately empty — no shortMessage, no metaMessages
    const cause = new BaseError('');
    throw new ContractFunctionExecutionError(cause, { abi: [], functionName: 'transferWithAuthorization' });
  });
  const result = await settleOnChain(makePayload(), SIGNER_ADDR, makeOpts({ publicClient }));
  // Must NOT classify as authorization_already_used_onchain
  expect(result).toMatchObject({ ok: false, reason: 'gas_estimate_revert' });
  expect(result).not.toMatchObject({ reason: 'authorization_already_used_onchain' });
});

